class Solution:
    def canEat(self, candiesCount, queries):
        pref = [0]
        for c in candiesCount:
            pref.append(pref[-1] + c)
        res = []
        for t, day, cap in queries:
            min_eaten = day + 1
            max_eaten = (day + 1) * cap
            lo = pref[t] + 1
            hi = pref[t + 1]
            res.append(min_eaten <= hi and max_eaten >= lo)
        return res

