class Solution:
    def canEat(self, candiesCount, queries):
        pref = [0] * (len(candiesCount) + 1)
        for i, c in enumerate(candiesCount):
            pref[i + 1] = pref[i] + c
        ans = []
        for t, day, cap in queries:
            ans.append(pref[t] < (day + 1) * cap and day + 1 <= pref[t + 1])
        return ans

