var canEat = function(candiesCount, queries) {
    const pref = new Array(candiesCount.length + 1).fill(0);
    for (let i = 0; i < candiesCount.length; i++) pref[i + 1] = pref[i] + candiesCount[i];
    return queries.map(([t, day, cap]) => pref[t] < (day + 1) * cap && day + 1 <= pref[t + 1]);
};
